import React, { useState } from 'react';

const campos = [
  { name: 'CN', label: 'CN' },
  { name: 'DadoInformado', label: 'Dado Informado' },
  { name: 'Servico', label: 'Serviço' },
  { name: 'UF', label: 'UF' },
  { name: 'Valores', label: 'Valores' },
  { name: 'CNPJ', label: 'CNPJ' },
  { name: 'DATA', label: 'DATA' },
];

const opcoesDadoInformado = [
  'Receita_Operacional_Líqu',
  'Capital_Expenditure_CAPI',
  'Tráfego_Dados_Total_MB',
];

const opcoesServico = ['SCM', 'SeAC', 'OUTROS'];
const opcoesUF = [
  'AC','AL','AP','AM','BA','CE','DF','ES','GO','MA','MT','MS','MG','PA','PB','PR','PE','PI','RJ','RN','RS','RO','RR','SC','SP','SE','TO'
];

export default function TabelaRelatorioEconomico({ cnpjPadrao, dataPadrao, datasPadrao }) {
  // Busca o CNPJ do cliente do card (localStorage)
  let cnpjCliente = cnpjPadrao;
  try {
    const salvo = localStorage.getItem('clienteSelecionado');
    if (salvo) {
      const obj = JSON.parse(salvo);
      if (obj.cnpj) cnpjCliente = obj.cnpj;
    }
  } catch {}

  const [linhas, setLinhas] = useState([
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[0] : (dataPadrao || '') },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[1] : (dataPadrao || '') },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[2] : (dataPadrao || '') },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[3] : (dataPadrao || '') },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[4] : (dataPadrao || '') },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[5] : (dataPadrao || '') },
  ]);

  const [linhasSalvas, setLinhasSalvas] = useState([]);
  const handleSalvarLinhas = () => {
    setLinhasSalvas([...linhasSalvas, ...linhas]);
    setLinhas([
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[0] : (dataPadrao || '') },
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[1] : (dataPadrao || '') },
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[2] : (dataPadrao || '') },
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[3] : (dataPadrao || '') },
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[4] : (dataPadrao || '') },
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: datasPadrao ? datasPadrao[5] : (dataPadrao || '') },
    ]);
  };

  const handleChange = (idx, campo, valor) => {
    setLinhas(linhas => linhas.map((linha, i) => i === idx ? { ...linha, [campo]: valor } : linha));
  };

  const handleCSV = () => {
    const header = campos.map(c => c.label).join(';');
    const rows = linhasSalvas.map(linha => campos.map(c => linha[c.name]).join(';'));
    const csv = [header, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', 'relatorio_economico.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAdicionarLinha = () => {
    setLinhas(linhas => ([
      ...linhas,
      { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjCliente || '', DATA: '' }
    ]));
  };

  return (
    <div style={{background:'#fff',padding:24,borderRadius:12,boxShadow:'0 2px 8px #0001',maxWidth:1200,margin:'2rem auto'}}>
      <h2>Formulário</h2>
      <table style={{width:'100%',marginBottom:16}}>
        <thead>
          <tr>
            {campos.map(c => (
              <th key={c.name} style={{
                width: ["CN","UF","Valores","CNPJ","DATA"].includes(c.name) ? (
                  c.name === "CN" ? 40 :
                  c.name === "UF" ? 50 :
                  c.name === "Valores" ? 80 :
                  c.name === "CNPJ" ? 120 :
                  c.name === "DATA" ? 90 : undefined
                ) : undefined
              }}>{c.label}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {linhas.map((linha, idx) => (
            <tr key={idx}>
              <td><input value={linha.CN} onChange={e => handleChange(idx, 'CN', e.target.value)} style={{width:40}} /></td>
              <td>
                <select value={linha.DadoInformado} onChange={e => handleChange(idx, 'DadoInformado', e.target.value)}>
                  <option value="">Selecione</option>
                  {opcoesDadoInformado.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </td>
              <td>
                <select value={linha.Servico} onChange={e => handleChange(idx, 'Servico', e.target.value)}>
                  {opcoesServico.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </td>
              <td>
                <select value={linha.UF} onChange={e => handleChange(idx, 'UF', e.target.value)} style={{width:50}}>
                  <option value="">Selecione</option>
                  {opcoesUF.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </td>
              <td>
                <input
                  value={linha.Valores}
                  onChange={e => {
                    let valor = e.target.value.replace(/[^0-9]/g, '');
                    if (!valor) valor = '0';
                    // Converte para formato 0,00
                    valor = (parseInt(valor, 10) / 100).toFixed(2).replace('.', ',');
                    handleChange(idx, 'Valores', valor);
                  }}
                  placeholder="0,00"
                  style={{background: linha.Valores ? undefined : '#f5f5f5', width:80}}
                  inputMode="numeric"
                />
              </td>
              <td><input value={linha.CNPJ} onChange={e => handleChange(idx, 'CNPJ', e.target.value)} placeholder={cnpjCliente || ''} style={{width:120}} /></td>
              <td><input value={linha.DATA} onChange={e => handleChange(idx, 'DATA', e.target.value)} style={{width:90}} /></td>
            </tr>
          ))}
        </tbody>
      </table>
      <button onClick={handleAdicionarLinha} style={{background:'#1976d2',color:'#fff',border:'none',borderRadius:4,padding:'0.7rem 2rem',fontWeight:'bold',fontSize:16,cursor:'pointer',marginRight:12}}>Adicionar Linha</button>
      <button onClick={handleSalvarLinhas} style={{background:'#388e3c',color:'#fff',border:'none',borderRadius:4,padding:'0.7rem 2rem',fontWeight:'bold',fontSize:16,cursor:'pointer',marginRight:12}}>Salvar Linhas</button>
      <button onClick={handleCSV} style={{background:'#d32f2f',color:'#fff',border:'none',borderRadius:4,padding:'0.7rem 2rem',fontWeight:'bold',fontSize:16,cursor:'pointer'}}>Gerar CSV</button>

      {linhasSalvas.length > 0 && (
        <div style={{marginTop:32}}>
          <h3>Linhas Salvas</h3>
          <table style={{width:'100%',background:'#f4f4f4',borderRadius:6,padding:8}}>
            <thead>
              <tr>
                {campos.map(c => <th key={c.name}>{c.label}</th>)}
              </tr>
            </thead>
            <tbody>
              {linhasSalvas.map((linha, idx) => (
                <tr key={idx}>
                  {campos.map(c => <td key={c.name}>{linha[c.name]}</td>)}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
